-- ============================================================
-- TRAINING CLIENTS - Assign clients to sessions
-- ============================================================
INSERT INTO training_client (training_id, client_id)
SELECT 'ts000000-0000-0000-0000-000000000001', id FROM client_profiles WHERE id IN ('q0000000-0000-0000-0000-000000000001', 'q0000000-0000-0000-0000-000000000002', 'q0000000-0000-0000-0000-000000000003')
UNION ALL SELECT 'ts000000-0000-0000-0000-000000000002', id FROM client_profiles WHERE id IN ('q0000000-0000-0000-0000-000000000002', 'q0000000-0000-0000-0000-000000000004')
UNION ALL SELECT 'ts000000-0000-0000-0000-000000000003', id FROM client_profiles WHERE id IN ('q0000000-0000-0000-0000-000000000001', 'q0000000-0000-0000-0000-000000000005', 'q0000000-0000-0000-0000-000000000006')
UNION ALL SELECT 'ts000000-0000-0000-0000-000000000004', id FROM client_profiles WHERE id IN ('q0000000-0000-0000-0000-000000000001', 'q0000000-0000-0000-0000-000000000003')
UNION ALL SELECT 'ts000000-0000-0000-0000-000000000005', id FROM client_profiles WHERE id IN ('q0000000-0000-0000-0000-000000000002')
UNION ALL SELECT 'ts000000-0000-0000-0000-000000000006', id FROM client_profiles WHERE id IN ('q0000000-0000-0000-0000-000000000001', 'q0000000-0000-0000-0000-000000000005', 'q0000000-0000-0000-0000-000000000007')
UNION ALL SELECT 'ts000000-0000-0000-0000-000000000007', id FROM client_profiles WHERE id IN ('q0000000-0000-0000-0000-000000000001', 'q0000000-0000-0000-0000-000000000002', 'q0000000-0000-0000-0000-000000000006')
UNION ALL SELECT 'ts000000-0000-0000-0000-000000000008', id FROM client_profiles WHERE id IN ('q0000000-0000-0000-0000-000000000002', 'q0000000-0000-0000-0000-000000000004')
UNION ALL SELECT 'ts000000-0000-0000-0000-000000000009', id FROM client_profiles WHERE id IN ('q0000000-0000-0000-0000-000000000003', 'q0000000-0000-0000-0000-000000000005')
UNION ALL SELECT 'ts000000-0000-0000-0000-000000000010', id FROM client_profiles WHERE id IN ('q0000000-0000-0000-0000-000000000004', 'q0000000-0000-0000-0000-000000000006', 'q0000000-0000-0000-0000-000000000008');

-- ============================================================
-- ATTENDANCES - For completed sessions (realistic attendance ~60-80%)
-- ============================================================
INSERT INTO attendances (id, session_id, client_id, check_in_time, created_date, created_by)
SELECT
    'a' || SUBSTRING(tc.training_id FROM 25 FOR 12) || SUBSTRING(c.id FROM 25 FOR 12),
    tc.training_id,
    c.id,
    s.start_time,
    s.start_time,
    'SYSTEM'
FROM training_client tc
JOIN training_sessions s ON s.id = tc.training_id
JOIN client_profiles c ON c.id = tc.client_id
WHERE tc.training_id IN (
    'ts000000-0000-0000-0000-000000000001', 'ts000000-0000-0000-0000-000000000002',
    'ts000000-0000-0000-0000-000000000003', 'ts000000-0000-0000-0000-000000000004',
    'ts000000-0000-0000-0000-000000000005', 'ts000000-0000-0000-0000-000000000006',
    'ts000000-0000-0000-0000-000000000007', 'ts000000-0000-0000-0000-000000000008',
    'ts000000-0000-0000-0000-000000000009', 'ts000000-0000-0000-0000-000000000010',
    'ts000000-0000-0000-0000-000000000121', 'ts000000-0000-0000-0000-000000000122',
    'ts000000-0000-0000-0000-000000000123'
)
AND RANDOM() < 0.75;
